// C# — BFS on Graph (Adjacency List)
// Iterative BFS, Search for X, Shortest Path, Count Components, Level Order
using System.Collections.Generic;

public class Graph
{
    private readonly Dictionary<int, List<int>> _adjList = new();

    public void AddEdge(int u, int v)
    {
        if (!_adjList.ContainsKey(u)) _adjList[u] = new List<int>();
        if (!_adjList.ContainsKey(v)) _adjList[v] = new List<int>();
        _adjList[u].Add(v);
        _adjList[v].Add(u);
    }

    // Iterative BFS — traverse all reachable nodes from start
    public void BFS(int start)
    {
        var visited = new HashSet<int>();
        var queue = new Queue<int>();
        visited.Add(start);
        queue.Enqueue(start);
        while (queue.Count > 0)
        {
            int node = queue.Dequeue();
            Console.Write(node + " ");
            foreach (var neighbor in _adjList.GetValueOrDefault(node, new List<int>()))
            {
                if (!visited.Contains(neighbor))
                {
                    visited.Add(neighbor);
                    queue.Enqueue(neighbor);
                }
            }
        }
    }

    // Search for item X — returns true if found
    public bool SearchFor(int target)
    {
        var visited = new HashSet<int>();
        foreach (var start in _adjList.Keys)
        {
            if (visited.Contains(start)) continue;
            var queue = new Queue<int>();
            visited.Add(start);
            queue.Enqueue(start);
            while (queue.Count > 0)
            {
                int node = queue.Dequeue();
                if (node == target) return true;
                foreach (var neighbor in _adjList.GetValueOrDefault(node, new List<int>()))
                    if (!visited.Contains(neighbor))
                    {
                        visited.Add(neighbor);
                        queue.Enqueue(neighbor);
                    }
            }
        }
        return false;
    }

    // Find Shortest Path — returns list of nodes or null if no path
    public List<int>? FindShortestPath(int src, int dest)
    {
        var visited = new HashSet<int>();
        var parent = new Dictionary<int, int>();
        var queue = new Queue<int>();
        visited.Add(src);
        queue.Enqueue(src);
        while (queue.Count > 0)
        {
            int node = queue.Dequeue();
            if (node == dest)
            {
                // reconstruct path
                var path = new List<int>();
                int cur = dest;
                while (cur != src) { path.Add(cur); cur = parent[cur]; }
                path.Add(src);
                path.Reverse();
                return path;
            }
            foreach (var neighbor in _adjList.GetValueOrDefault(node, new List<int>()))
                if (!visited.Contains(neighbor))
                {
                    visited.Add(neighbor);
                    parent[neighbor] = node;
                    queue.Enqueue(neighbor);
                }
        }
        return null;
    }

    // Count Connected Components
    public int CountComponents()
    {
        var visited = new HashSet<int>();
        int count = 0;
        foreach (var start in _adjList.Keys)
        {
            if (visited.Contains(start)) continue;
            var queue = new Queue<int>();
            visited.Add(start);
            queue.Enqueue(start);
            while (queue.Count > 0)
            {
                int node = queue.Dequeue();
                foreach (var neighbor in _adjList.GetValueOrDefault(node, new List<int>()))
                    if (!visited.Contains(neighbor))
                    {
                        visited.Add(neighbor);
                        queue.Enqueue(neighbor);
                    }
            }
            count++;
        }
        return count;
    }

    // Level Order Traversal — returns nodes grouped by level
    public List<List<int>> LevelOrder(int start)
    {
        var result = new List<List<int>>();
        var visited = new HashSet<int>();
        var queue = new Queue<int>();
        visited.Add(start);
        queue.Enqueue(start);
        while (queue.Count > 0)
        {
            int levelSize = queue.Count;
            var level = new List<int>();
            for (int i = 0; i < levelSize; i++)
            {
                int node = queue.Dequeue();
                level.Add(node);
                foreach (var neighbor in _adjList.GetValueOrDefault(node, new List<int>()))
                    if (!visited.Contains(neighbor))
                    {
                        visited.Add(neighbor);
                        queue.Enqueue(neighbor);
                    }
            }
            result.Add(level);
        }
        return result;
    }
}

