import java.util.*;

public class Graph {
    private final Map<Integer, List<Integer>> adjList = new HashMap<>();

    public void addEdge(int u, int v) {
        adjList.computeIfAbsent(u, k -> new ArrayList<>()).add(v);
        adjList.computeIfAbsent(v, k -> new ArrayList<>()).add(u);
    }

    // Iterative BFS
    public void bfs(int start) {
        Set<Integer> visited = new HashSet<>();
        Queue<Integer> queue = new LinkedList<>();
        visited.add(start);
        queue.add(start);
        while (!queue.isEmpty()) {
            int node = queue.poll();
            System.out.print(node + " ");
            for (int neighbor : adjList.getOrDefault(node, Collections.emptyList()))
                if (!visited.contains(neighbor)) {
                    visited.add(neighbor);
                    queue.add(neighbor);
                }
        }
    }

    // Search for item X
    public boolean searchFor(int target) {
        Set<Integer> visited = new HashSet<>();
        for (int start : adjList.keySet()) {
            if (visited.contains(start)) continue;
            Queue<Integer> queue = new LinkedList<>();
            visited.add(start);
            queue.add(start);
            while (!queue.isEmpty()) {
                int node = queue.poll();
                if (node == target) return true;
                for (int neighbor : adjList.getOrDefault(node, Collections.emptyList()))
                    if (!visited.contains(neighbor)) {
                        visited.add(neighbor);
                        queue.add(neighbor);
                    }
            }
        }
        return false;
    }

    // Find Shortest Path
    public List<Integer> findShortestPath(int src, int dest) {
        Set<Integer> visited = new HashSet<>();
        Map<Integer, Integer> parent = new HashMap<>();
        Queue<Integer> queue = new LinkedList<>();
        visited.add(src);
        queue.add(src);
        while (!queue.isEmpty()) {
            int node = queue.poll();
            if (node == dest) {
                List<Integer> path = new ArrayList<>();
                int cur = dest;
                while (cur != src) { path.add(cur); cur = parent.get(cur); }
                path.add(src);
                Collections.reverse(path);
                return path;
            }
            for (int neighbor : adjList.getOrDefault(node, Collections.emptyList()))
                if (!visited.contains(neighbor)) {
                    visited.add(neighbor);
                    parent.put(neighbor, node);
                    queue.add(neighbor);
                }
        }
        return null;
    }

    // Count Connected Components
    public int countComponents() {
        Set<Integer> visited = new HashSet<>();
        int count = 0;
        for (int start : adjList.keySet()) {
            if (visited.contains(start)) continue;
            Queue<Integer> queue = new LinkedList<>();
            visited.add(start);
            queue.add(start);
            while (!queue.isEmpty()) {
                int node = queue.poll();
                for (int neighbor : adjList.getOrDefault(node, Collections.emptyList()))
                    if (!visited.contains(neighbor)) {
                        visited.add(neighbor);
                        queue.add(neighbor);
                    }
            }
            count++;
        }
        return count;
    }

    // Level Order Traversal
    public List<List<Integer>> levelOrder(int start) {
        List<List<Integer>> result = new ArrayList<>();
        Set<Integer> visited = new HashSet<>();
        Queue<Integer> queue = new LinkedList<>();
        visited.add(start);
        queue.add(start);
        while (!queue.isEmpty()) {
            int levelSize = queue.size();
            List<Integer> level = new ArrayList<>();
            for (int i = 0; i < levelSize; i++) {
                int node = queue.poll();
                level.add(node);
                for (int neighbor : adjList.getOrDefault(node, Collections.emptyList()))
                    if (!visited.contains(neighbor)) {
                        visited.add(neighbor);
                        queue.add(neighbor);
                    }
            }
            result.add(level);
        }
        return result;
    }

    public static void main(String[] args) {
